export function tokenize(input){const tokens=[];let i=0;const isWhitespace=c=>c===" "||c==="\n"||c==="\t"||c==="\r";const isDigit=c=>c>="0"&&c<="9";const push=(type,value)=>{tokens.push({type,value})};const pushError=(raw)=>{tokens.push({type:"error",value:raw})};while(i<input.length){const ch=input[i];if(isWhitespace(ch)){const start=i;while(i<input.length&&isWhitespace(input[i]))i++;push("whitespace",input.slice(start,i));continue} if("{}[]:,".includes(ch)){push("punctuator",ch);i++;continue} if(ch==='"'){const start=i;i++;let value="";let closed=!1;while(i<input.length){const c=input[i];if(c==="\\"){const next=input[i+1];if(next==null){pushError(input.slice(start,i+1));return tokens} if(next==="u"){const hex=input.slice(i+2,i+6);if(!/^[0-9a-fA-F]{4}$/.test(hex)){pushError(input.slice(start,i+6));return tokens} value+=String.fromCharCode(parseInt(hex,16));i+=6;continue} value+=decodeEscape(next);i+=2;continue} if(c==='"'){closed=!0;i++;break} value+=c;i++} if(!closed){pushError(input.slice(start,i));return tokens} push("string",value);continue} if(ch==="-"||isDigit(ch)){const start=i;if(ch==="-")i++;if(input[i]==="0"){i++}else if(isDigit(input[i])){while(isDigit(input[i]))i++}else{pushError(input.slice(start,i+1));return tokens} if(input[i]==="."){i++;if(!isDigit(input[i])){pushError(input.slice(start,i+1));return tokens} while(isDigit(input[i]))i++} if(input[i]==="e"||input[i]==="E"){i++;if(input[i]==="+"||input[i]==="-")i++;if(!isDigit(input[i])){pushError(input.slice(start,i+1));return tokens} while(isDigit(input[i]))i++} push("number",Number(input.slice(start,i)));continue} if(input.startsWith("true",i)){push("boolean",!0);i+=4;continue} if(input.startsWith("false",i)){push("boolean",!1);i+=5;continue} if(input.startsWith("null",i)){push("null",null);i+=4;continue} pushError(ch);i++} return tokens} function decodeEscape(ch){switch(ch){case '"':return'"';case "\\":return"\\";case "/":return"/";case "b":return"\b";case "f":return"\f";case "n":return"\n";case "r":return"\r";case "t":return"\t";default:return"\\"+ch}}
